// ❌ BAD - DbContext as Singleton causes threading bugs and stale data
builder.Services.AddSingleton<AppDbContext>();

// ✅ GOOD - correct lifetimes matched to each service's role
builder.Services.AddSingleton<ICurrencyConverter, ExchangeRateService>();
builder.Services.AddScoped<IOrderRepository, OrderRepository>();
builder.Services.AddScoped<AppDbContext>();
builder.Services.AddTransient<IEmailFormatter, HtmlEmailFormatter>();

// ❌ BAD - hard-coded dependency, impossible to unit test or swap
public class OrderService
{
    private readonly SmtpEmailSender _email = new SmtpEmailSender();
}

// ✅ GOOD - depends on abstraction, injectable and testable
public class OrderService
{
    private readonly IEmailSender _email;
    public OrderService(IEmailSender email) => _email = email;
}

// ❌ BAD - Singleton captures Scoped DbContext, shared across all requests
public class ReportCacheService
{
    public ReportCacheService(InvoiceDbContext db) { } // captive!
}

// ✅ GOOD - create a scope on demand and dispose when done
public class ReportCacheService
{
    private readonly IServiceScopeFactory _scopeFactory;
    public ReportCacheService(IServiceScopeFactory scopeFactory)
        => _scopeFactory = scopeFactory;
    public async Task RebuildAsync()
    {
        using var scope = _scopeFactory.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<InvoiceDbContext>();
    }
}

// ❌ BAD - service locator inside business logic hides dependencies
public class ShipmentService
{
    private readonly IServiceProvider _sp;
    public ShipmentService(IServiceProvider sp) => _sp = sp;
    public void Ship() { var repo = _sp.GetService<IShipmentRepo>(); }
}

// ✅ GOOD - constructor injection, dependencies are explicit and testable
public class ShipmentService
{
    private readonly IShipmentRepo _repo;
    public ShipmentService(IShipmentRepo repo) => _repo = repo;
    public void Ship() => _repo.Save();
}

// ❌ BAD - property injection, object can be used before EmailSender is set
public class InvoiceService
{
    public IEmailSender EmailSender { get; set; } // nullable, hidden, mutable
    public void SendInvoice() => EmailSender.Send(); // NullReferenceException risk
}

// ✅ GOOD - constructor injection, dependency is required and immutable
public class InvoiceService
{
    private readonly IEmailSender _emailSender;
    public InvoiceService(IEmailSender emailSender)
        => _emailSender = emailSender;
    public void SendInvoice() => _emailSender.Send();
}

// ❌ BAD - inject all, filter by type - leaks concrete class into consumer
public class AlertService
{
    public AlertService(IEnumerable<INotificationChannel> all)
    { var sms = all.OfType<SmsChannel>().First(); }
}

// ✅ GOOD - .NET 8 keyed services, resolve exactly what you need
builder.Services.AddKeyedScoped<INotificationChannel, EmailChannel>("email");
builder.Services.AddKeyedScoped<INotificationChannel, SmsChannel>("sms");
public class AlertService
{
    public AlertService([FromKeyedServices("sms")] INotificationChannel sms) { }
}

// ❌ BAD - calling GetRequiredService on IServiceCollection before Build
var services = builder.Services;
var repo = services.GetRequiredService<IOrderRepo>(); // compile error - wrong type

// ✅ GOOD - resolve from the built IServiceProvider after Build()
var app = builder.Build();
using var scope = app.Services.CreateScope();
var repo = scope.ServiceProvider.GetRequiredService<IOrderRepo>();
